// ─── Utility Functions ────────────────────────────────────────────────────────

function loadGoogleFonts() {
  if (document.getElementById("gf-link")) return;
  const link = document.createElement("link");
  link.id = "gf-link";
  link.rel = "stylesheet";
  link.href = "https://fonts.googleapis.com/css2?family=Cormorant+Garamond:wght@300;400;500;600;700;800&family=DM+Sans:wght@300;400;500;700&display=swap";
  document.head.appendChild(link);
}

function wrapText(ctx, text, x, y, maxW, lineH, color, font, shadow, shadowColor, shadowSize, shadowType) {
  ctx.font = font;
  ctx.fillStyle = color;

  const isSolid = shadow && shadowType === "solid";

  if (shadow && !isSolid) {
    const sz = shadowSize ?? 8;
    ctx.shadowColor = shadowColor || "#1A1A1A";
    ctx.shadowBlur = sz;
    if (shadowType === "surround") {
      ctx.shadowOffsetX = 0;
      ctx.shadowOffsetY = 0;
    } else {
      ctx.shadowOffsetX = Math.round(sz * 0.4);
      ctx.shadowOffsetY = Math.round(sz * 0.4);
    }
  } else {
    ctx.shadowColor = "transparent";
    ctx.shadowBlur = 0;
    ctx.shadowOffsetX = 0;
    ctx.shadowOffsetY = 0;
  }

  if (isSolid) {
    ctx.strokeStyle = shadowColor || "#1A1A1A";
    ctx.lineWidth = (shadowSize ?? 8) * 2;
    ctx.lineJoin = "round";
  }

  const paragraphs = text.split("\n");
  let curY = y;
  for (const para of paragraphs) {
    const words = para.split(" ");
    let row = "";
    for (const word of words) {
      const test = row ? row + " " + word : word;
      if (ctx.measureText(test).width > maxW && row) {
        if (isSolid) ctx.strokeText(row, x, curY);
        ctx.fillText(row, x, curY);
        row = word;
        curY += lineH;
      } else { row = test; }
    }
    if (row) {
      if (isSolid) ctx.strokeText(row, x, curY);
      ctx.fillText(row, x, curY);
      curY += lineH;
    }
  }
  ctx.shadowColor = "transparent";
  ctx.shadowBlur = 0;
  ctx.shadowOffsetX = 0;
  ctx.shadowOffsetY = 0;
  ctx.lineWidth = 1;
}

function getLogoXY(posId, W, H, lw, lh, pad) {
  const col = { T: pad, M: (W - lw) / 2, B: W - lw - pad }[posId[0]];
  const row = { T: pad, M: (H - lh) / 2, B: H - lh - pad }[posId[1]];
  return { x: col, y: row };
}

function drawOnCanvas(canvas, state, logoSrc) {
  const {
    textLayers, bgSrc, showBg, solidColor,
    showGradient, gradColor, gradDirection, gradIntensity, gradLength,
    showLogo, logoPosition, logoOpacity, logoSize,
    goldRules, uploadedElements,
    selectedBadge, badgeSizePct, badgeXPct, badgeYPct,
    canvasW, canvasH,
  } = state;

  const W = canvasW;
  const H = canvasH;

  return new Promise(resolve => {
    const ctx = canvas.getContext("2d");
    canvas.width = W;
    canvas.height = H;
    const scale = Math.min(W / 1200, H / 640);
    const fs = (n) => Math.round(n * scale);

    const drawContent = (bgReady) => {
      // Background
      if (!showBg || !bgReady) {
        ctx.fillStyle = solidColor || C.SOFT_IVORY;
        ctx.fillRect(0, 0, W, H);
      }

      // Gradient overlay
      if (showGradient) {
        let grad;
        const intensity = (gradIntensity ?? 70) / 100;
        const hex = gradColor || C.DUSTY_PINE;
        const r = parseInt(hex.slice(1,3),16);
        const g = parseInt(hex.slice(3,5),16);
        const b = parseInt(hex.slice(5,7),16);
        if (gradDirection === "bottom") {
          grad = ctx.createLinearGradient(0, 0, 0, H);
        } else if (gradDirection === "top") {
          grad = ctx.createLinearGradient(0, H, 0, 0);
        } else if (gradDirection === "left") {
          grad = ctx.createLinearGradient(W, 0, 0, 0);
        } else {
          grad = ctx.createLinearGradient(0, 0, W, 0);
        }
        // length: 10% = short gradient at the edge, 100% = spans full canvas
        const len = (gradLength ?? 70) / 100;
        const startPos = Math.max(0, 1 - len);
        const midPos = Math.min(startPos + len * 0.5, 0.99);
        grad.addColorStop(startPos, `rgba(${r},${g},${b},0)`);
        grad.addColorStop(midPos, `rgba(${r},${g},${b},${intensity * 0.6})`);
        grad.addColorStop(1, `rgba(${r},${g},${b},${intensity})`);
        ctx.fillStyle = grad;
        ctx.fillRect(0, 0, W, H);
      }

      // Gold rules
      (goldRules || []).forEach(rule => {
        const ruleW = Math.round((rule.widthPct / 100) * W);
        const ruleY = Math.round((rule.yPct / 100) * H);
        const ruleX = Math.round(((rule.xPct ?? 0) / 100) * W);
        ctx.fillStyle = rule.color || C.HARVEST_GOLD;
        ctx.shadowColor = "transparent";
        ctx.fillRect(ruleX, ruleY, ruleW, Math.round(4 * scale));
      });

      // Text layers
      (textLayers || []).forEach(layer => {
        const x = Math.round((layer.xPct / 100) * W);
        const y = Math.round((layer.yPct / 100) * H);
        const fontStr = `${layer.weight} ${Math.max(12, Math.round(layer.size * W / 1200))}px ${layer.font}`;
        const lineH = Math.round(layer.size * W / 1200 * 1.3);
        const pad = Math.round(0.04 * W);

        let maxW;
        if (layer.align === "center") {
          ctx.textAlign = "center";
          // x is center anchor; wrap width is symmetric around it
          maxW = Math.min(x, W - x) * 2;
        } else if (layer.align === "right") {
          ctx.textAlign = "right";
          // x is right edge anchor; text wraps leftward from x
          maxW = x - pad;
        } else {
          ctx.textAlign = "left";
          maxW = W - x - pad;
        }

        wrapText(ctx, layer.text || "", x, y, Math.max(maxW, 80), lineH, layer.color, fontStr, layer.shadow, layer.shadowColor, layer.shadowSize, layer.shadowType);
        ctx.textAlign = "left";
      });

      // Uploaded elements + active badge
      const allElements = [...(uploadedElements || [])];
      if (selectedBadge) {
        allElements.push({ src: selectedBadge.src, sizePct: badgeSizePct ?? 50, xPct: badgeXPct ?? 5, yPct: badgeYPct ?? 10 });
      }
      const elemPromises = allElements.map(el => {
        return new Promise(res => {
          const img = new Image();
          img.onload = () => {
            const elW = Math.round((el.sizePct / 100) * W);
            const elH = Math.round(elW * img.height / img.width);
            const elX = Math.round((el.xPct / 100) * W);
            const elY = Math.round((el.yPct / 100) * H);
            ctx.drawImage(img, elX, elY, elW, elH);
            res();
          };
          img.onerror = res;
          img.src = el.src;
        });
      });

      Promise.all(elemPromises).then(() => {
        // Logo
        if (!showLogo || !logoSrc) { resolve(); return; }
        const lg = new Image();
        lg.onerror = resolve;
        lg.onload = () => {
          const lw = Math.round((logoSize ?? 16) / 100 * W);
          const lh = Math.round(lw * lg.height / lg.width);
          const pad = Math.round(0.04 * W);
          const pos = logoPosition || "TR";
          const colKey = pos[1] === "L" ? "T" : pos[1] === "C" ? "M" : "B";
          const rowKey = pos[0];
          const lx = colKey === "T" ? pad : colKey === "M" ? (W - lw) / 2 : W - lw - pad;
          const ly = rowKey === "T" ? pad : rowKey === "M" ? (H - lh) / 2 : H - lh - pad;
          ctx.globalAlpha = (logoOpacity ?? 100) / 100;
          ctx.shadowColor = "transparent";
          ctx.drawImage(lg, lx, ly, lw, lh);
          ctx.globalAlpha = 1;
          resolve();
        };
        lg.src = logoSrc;
      });
    };

    if (!showBg || !bgSrc) {
      drawContent(false);
      return;
    }

    const img = new Image();
    img.onerror = () => { drawContent(false); };
    img.onload = () => {
      const iAR = img.width / img.height;
      const cAR = W / H;
      let sx = 0, sy = 0, sw = img.width, sh = img.height;
      if (iAR > cAR) { sw = img.height * cAR; sx = (img.width - sw) / 2; }
      else { sh = img.width / cAR; sy = (img.height - sh) / 2; }
      ctx.drawImage(img, sx, sy, sw, sh, 0, 0, W, H);
      drawContent(true);
    };
    img.src = bgSrc;
  });
}

// ─── Sub-components ───────────────────────────────────────────────────────────

function Section({ title, children, collapsible = false }) {
  const [open, setOpen] = React.useState(true);
  return (
    <div style={{ marginBottom: 26 }}>
      <div
        onClick={collapsible ? () => setOpen(o => !o) : undefined}
        style={{
          display: "flex", justifyContent: "space-between", alignItems: "center",
          marginBottom: 12, cursor: collapsible ? "pointer" : "default",
          userSelect: "none",
        }}
      >
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          <div style={{ width: 3, height: 13, borderRadius: 2, background: C.HARVEST_GOLD, flexShrink: 0 }} />
          <span style={{ fontSize: 10, fontWeight: 700, color: "#9A9087", letterSpacing: "0.14em", textTransform: "uppercase" }}>{title}</span>
        </div>
        {collapsible && (
          <span style={{ fontSize: 16, color: "#B0A89E", fontWeight: 400, lineHeight: 1 }}>{open ? "−" : "+"}</span>
        )}
      </div>
      {(!collapsible || open) && children}
    </div>
  );
}

function ColorSwatch({ color, selected, onClick, size = 28 }) {
  return (
    <div
      onClick={onClick}
      title={color}
      style={{
        width: size, height: size, borderRadius: 6,
        background: color,
        border: `2px solid ${selected ? C.HARVEST_GOLD : "rgba(0,0,0,0.08)"}`,
        cursor: "pointer",
        boxShadow: selected
          ? `0 0 0 3px rgba(229,169,77,0.35), 0 2px 6px rgba(0,0,0,0.15)`
          : "0 1px 3px rgba(0,0,0,0.12)",
        transform: selected ? "scale(1.1)" : "scale(1)",
        transition: "transform 0.12s, box-shadow 0.12s",
      }}
    />
  );
}

function TextLayerEditor({ layer, index, onChange, onRemove }) {
  const [open, setOpen] = React.useState(true);
  const update = (key, val) => onChange(layer.id, { ...layer, [key]: val });

  return (
    <div style={{ border: "1px solid #E8E3DA", borderRadius: 10, overflow: "hidden", marginBottom: 10, boxShadow: "0 1px 4px rgba(0,0,0,0.04)" }}>
      <div
        onClick={() => setOpen(o => !o)}
        style={{
          display: "flex", justifyContent: "space-between", alignItems: "center",
          padding: "10px 14px", cursor: "pointer",
          background: open ? "linear-gradient(135deg, #F6F4E8 0%, #EDE9DC 100%)" : "#FAFAF7",
        }}
      >
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          <div style={{ width: 10, height: 10, borderRadius: "50%", background: layer.color, border: "1.5px solid rgba(0,0,0,0.1)", flexShrink: 0 }} />
          <span style={{ fontSize: 12, fontWeight: 600, color: C.TAUPE }}>{layer.label || `Text ${index + 1}`}</span>
          <span style={{ fontSize: 10, color: "#B0A89E", background: "#fff", borderRadius: 4, padding: "1px 6px", border: "1px solid #E8E3DA" }}>{layer.size}px</span>
        </div>
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          <span style={{ fontSize: 15, color: "#C0B8AE", fontWeight: 400 }}>{open ? "−" : "+"}</span>
          <span
            onClick={e => { e.stopPropagation(); onRemove(layer.id); }}
            style={{ fontSize: 13, color: "#D08080", cursor: "pointer", fontWeight: 700, lineHeight: 1, padding: "2px 4px", borderRadius: 4, background: "#FFF0F0" }}
          >×</span>
        </div>
      </div>
      {open && (
        <div style={{ padding: "14px 16px", display: "flex", flexDirection: "column", gap: 12, background: "#fff" }}>
          {/* Text */}
          <div>
            <div style={labelSt}>Text</div>
            <textarea
              value={layer.text}
              onChange={e => update("text", e.target.value)}
              rows={2}
              style={{ ...inputSt, resize: "vertical", marginTop: 3 }}
            />
          </div>
          {/* Font */}
          <div>
            <div style={labelSt}>Font</div>
            <div style={{ display: "flex", gap: 6 }}>
              {FONT_FAMILIES.map(f => (
                <button
                  key={f.css}
                  onClick={() => update("font", f.css)}
                  style={{
                    flex: 1, padding: "6px 4px", borderRadius: 6,
                    border: `2px solid ${layer.font === f.css ? C.HARVEST_GOLD : "#3F6B5530"}`,
                    background: layer.font === f.css ? "#E5A94D22" : "transparent",
                    fontSize: 11, color: C.TAUPE, cursor: "pointer", fontFamily: f.css, fontWeight: 600,
                  }}
                >
                  {f.name.split(" ")[0]}
                </button>
              ))}
            </div>
          </div>
          {/* Weight */}
          <div>
            <div style={labelSt}>Weight</div>
            <div style={{ display: "flex", flexWrap: "wrap", gap: 5 }}>
              {FONT_WEIGHTS.map(w => (
                <button
                  key={w.value}
                  onClick={() => update("weight", w.value)}
                  style={{
                    padding: "4px 8px", borderRadius: 5,
                    border: `1.5px solid ${layer.weight === w.value ? C.HARVEST_GOLD : "#3F6B5530"}`,
                    background: layer.weight === w.value ? "#E5A94D22" : "transparent",
                    fontSize: 11, color: C.TAUPE, cursor: "pointer",
                  }}
                >
                  {w.name}
                </button>
              ))}
            </div>
          </div>
          {/* Size */}
          <div>
            <div style={labelSt}>Size — {layer.size}px</div>
            <input
              type="range" min={12} max={180} value={layer.size}
              onChange={e => update("size", +e.target.value)}
              style={{ width: "100%", accentColor: C.HARVEST_GOLD }}
            />
          </div>
          {/* Color */}
          <div>
            <div style={labelSt}>Color</div>
            <div style={{ display: "flex", flexWrap: "wrap", gap: 6 }}>
              {BRAND_COLORS.map(bc => (
                <ColorSwatch key={bc.hex} color={bc.hex} selected={layer.color === bc.hex} onClick={() => update("color", bc.hex)} />
              ))}
            </div>
          </div>
          {/* Alignment */}
          <div>
            <div style={labelSt}>Alignment</div>
            <div style={{ display: "flex", gap: 6 }}>
              {["left","center","right"].map(a => (
                <button
                  key={a}
                  onClick={() => {
                    const defaultX = a === "center" ? 50 : a === "right" ? 94 : 6;
                    onChange(layer.id, { ...layer, align: a, xPct: defaultX });
                  }}
                  style={{
                    flex: 1, padding: "5px", borderRadius: 6,
                    border: `1.5px solid ${layer.align === a ? C.HARVEST_GOLD : "#3F6B5530"}`,
                    background: layer.align === a ? "#E5A94D22" : "transparent",
                    fontSize: 13, cursor: "pointer",
                  }}
                >
                  {a === "left" ? "⬅" : a === "center" ? "↔" : "➡"}
                </button>
              ))}
            </div>
          </div>
          {/* Shadow */}
          <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
            <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
              <span style={{ fontSize: 11, fontWeight: 600, color: C.TAUPE }}>Shadow</span>
              <div style={{ display: "flex", gap: 6 }}>
                {[{l:"On",v:true},{l:"Off",v:false}].map(opt => (
                  <button
                    key={opt.l}
                    onClick={() => update("shadow", opt.v)}
                    style={{
                      padding: "4px 12px", borderRadius: 5,
                      border: `1.5px solid ${layer.shadow === opt.v ? C.HARVEST_GOLD : "#3F6B5530"}`,
                      background: layer.shadow === opt.v ? "#E5A94D22" : "transparent",
                      fontSize: 11, color: C.TAUPE, cursor: "pointer",
                    }}
                  >{opt.l}</button>
                ))}
              </div>
            </div>
            {layer.shadow && (
              <>
                {/* Shadow color */}
                <div style={{ display: "flex", gap: 4 }}>
                  {["#1A1A1A","#FFFEF6","#3F6B55","#635752"].map(sc => (
                    <div
                      key={sc}
                      onClick={() => update("shadowColor", sc)}
                      style={{
                        width: 18, height: 18, borderRadius: 3, background: sc,
                        border: `2px solid ${layer.shadowColor === sc ? C.HARVEST_GOLD : "#ccc"}`,
                        cursor: "pointer",
                      }}
                    />
                  ))}
                </div>
                {/* Shadow type */}
                <div style={{ display: "flex", gap: 6 }}>
                  {[{l:"Side",v:"side"},{l:"Surround",v:"surround"},{l:"Solid",v:"solid"}].map(opt => (
                    <button
                      key={opt.v}
                      onClick={() => update("shadowType", opt.v)}
                      style={{
                        flex: 1, padding: "4px 8px", borderRadius: 5,
                        border: `1.5px solid ${(layer.shadowType || "side") === opt.v ? C.HARVEST_GOLD : "#3F6B5530"}`,
                        background: (layer.shadowType || "side") === opt.v ? "#E5A94D22" : "transparent",
                        fontSize: 11, color: C.TAUPE, cursor: "pointer",
                      }}
                    >{opt.l}</button>
                  ))}
                </div>
                {/* Shadow size */}
                <div>
                  <div style={labelSt}>Size — {layer.shadowSize ?? 8}px</div>
                  <input
                    type="range" min={1} max={40} value={layer.shadowSize ?? 8}
                    onChange={e => update("shadowSize", +e.target.value)}
                    style={{ width: "100%", accentColor: C.HARVEST_GOLD }}
                  />
                </div>
              </>
            )}
          </div>
          {/* Position */}
          <div>
            <div style={labelSt}>Position X — {layer.xPct}%</div>
            <input
              type="range" min={0} max={95} value={layer.xPct}
              onChange={e => update("xPct", +e.target.value)}
              style={{ width: "100%", accentColor: C.HARVEST_GOLD }}
            />
          </div>
          <div>
            <div style={labelSt}>Position Y — {layer.yPct}%</div>
            <input
              type="range" min={2} max={98} value={layer.yPct}
              onChange={e => update("yPct", +e.target.value)}
              style={{ width: "100%", accentColor: C.HARVEST_GOLD }}
            />
          </div>
        </div>
      )}
    </div>
  );
}

const labelSt = { fontSize: 10, fontWeight: 700, color: "#9A9087", textTransform: "uppercase", letterSpacing: "0.11em", marginBottom: 6 };
const inputSt = { width: "100%", padding: "9px 12px", borderRadius: 8, border: "1px solid #DDD8CE", background: "#FDFCF9", color: C.TAUPE, fontSize: 13, fontFamily: "'DM Sans',Inter,sans-serif", outline: "none", boxSizing: "border-box", boxShadow: "inset 0 1px 2px rgba(0,0,0,0.04)" };

// ─── Main Component ───────────────────────────────────────────────────────────

export default function DealFlowPostBuilder() {
  // Canvas size
  const [canvasSizeIdx, setCanvasSizeIdx] = useState(4); // default: Landmodo 1200x640
  const [customW, setCustomW] = useState(1200);
  const [customH, setCustomH] = useState(640);

  const getWH = () => {
    const sz = CANVAS_SIZES[canvasSizeIdx];
    if (sz.w === null) return { w: customW, h: customH };
    return { w: sz.w, h: sz.h };
  };

  // Background
  const [bgIdx, setBgIdx] = useState(0);
  const [customBgs, setCustomBgs] = useState([]);
  const [showBg, setShowBg] = useState(true);
  const [solidColor, setSolidColor] = useState(C.SOFT_IVORY);

  // Gradient
  const [showGradient, setShowGradient] = useState(true);
  const [gradColor, setGradColor] = useState(C.DUSTY_PINE);
  const [gradDirection, setGradDirection] = useState("bottom");
  const [gradIntensity, setGradIntensity] = useState(70);
  const [gradLength, setGradLength] = useState(70);

  // Logo
  const [showLogo, setShowLogo] = useState(true);
  const [logoPosition, setLogoPosition] = useState("TR");
  const [logoOpacity, setLogoOpacity] = useState(100);
  const [logoSize, setLogoSize] = useState(16);

  // Text layers
  const [textLayers, setTextLayers] = useState([
    defaultTextLayer(0),
    defaultTextLayer(1),
  ]);

  // Elements (uploaded images/badges)
  const [uploadedElements, setUploadedElements] = useState([]);

  // Built-in badge selection (null = none)
  const [selectedBadge, setSelectedBadge] = useState(null);
  const [badgeSizePct, setBadgeSizePct] = useState(50);
  const [badgeXPct, setBadgeXPct] = useState(5);
  const [badgeYPct, setBadgeYPct] = useState(10);

  // Gold rules
  const [goldRules, setGoldRules] = useState([]);

  // Tabs
  const [tab, setTab] = useState("build");

  // Prompt tab state
  const [promptDesc, setPromptDesc] = useState("");
  const [refImageData, setRefImageData] = useState(null);
  const [refImageDesc, setRefImageDesc] = useState("");
  const [generatedPrompt, setGeneratedPrompt] = useState("");
  const [copied, setCopied] = useState(false);

  // Templates collapsed
  const [templatesOpen, setTemplatesOpen] = useState(false);

  // Export state
  const [exporting, setExporting] = useState(false);

  const previewRef = useRef(null);
  const bgFileRef = useRef(null);
  const elemFileRef = useRef(null);
  const refImageRef = useRef(null);

  const allBgs = [...BUILTIN_BGS, ...customBgs];
  const activeBg = allBgs[bgIdx] || allBgs[0];

  useEffect(() => { loadGoogleFonts(); }, []);

  const { w: canvasW, h: canvasH } = getWH();

  const canvasState = {
    textLayers, bgSrc: activeBg?.src, showBg, solidColor,
    showGradient, gradColor, gradDirection, gradIntensity, gradLength,
    showLogo, logoPosition, logoOpacity, logoSize,
    goldRules, uploadedElements,
    selectedBadge, badgeSizePct, badgeXPct, badgeYPct,
    canvasW, canvasH,
  };

  useEffect(() => {
    if (!previewRef.current) return;
    drawOnCanvas(previewRef.current, canvasState, LOGO);
  }, [
    textLayers, bgIdx, customBgs, showBg, solidColor,
    showGradient, gradColor, gradDirection, gradIntensity, gradLength,
    showLogo, logoPosition, logoOpacity, logoSize,
    goldRules, uploadedElements,
    selectedBadge, badgeSizePct, badgeXPct, badgeYPct,
    canvasW, canvasH,
  ]);

  // ── Handlers ──

  const addTextLayer = () => {
    setTextLayers(prev => [...prev, defaultTextLayer(prev.length)]);
  };

  const updateTextLayer = (id, updated) => {
    setTextLayers(prev => prev.map(l => l.id === id ? updated : l));
  };

  const removeTextLayer = (id) => {
    setTextLayers(prev => prev.filter(l => l.id !== id));
  };

  const handleUploadBg = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => {
      const newBg = { label: file.name.replace(/\.[^.]+$/, ""), src: ev.target.result, custom: true };
      setCustomBgs(prev => {
        setBgIdx(BUILTIN_BGS.length + prev.length);
        return [...prev, newBg];
      });
    };
    reader.readAsDataURL(file);
    e.target.value = "";
  };

  const handleUploadElement = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => {
      setUploadedElements(prev => [...prev, {
        id: Date.now(),
        src: ev.target.result,
        label: file.name.replace(/\.[^.]+$/, ""),
        sizePct: 20,
        xPct: 40,
        yPct: 40,
      }]);
    };
    reader.readAsDataURL(file);
    e.target.value = "";
  };

  const handleRefImage = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => setRefImageData(ev.target.result);
    reader.readAsDataURL(file);
    e.target.value = "";
  };

  const buildPrompt = () => {
    const raw = promptDesc.trim();
    const desc = raw || "wide open vacant land at golden hour";

    // Reference image block
    const refBlock = refImageData
      ? `Reference image provided: YES — attach this image alongside this prompt in Gemini.
${refImageDesc.trim() ? `What the reference image shows: ${refImageDesc.trim()}
Recreate a similar scene — same general composition, lighting mood, and landscape feel — adapted to the DealFlow OH brand aesthetic described below.` : `Use the attached reference image as a visual inspiration for scene composition, lighting angle, and landscape character. Recreate a similar feel adapted to the DealFlow OH brand.`}`
      : "";

    // Detect which land types appear in the description
    const matchedTypes = LAND_TYPES.filter(t => raw.toLowerCase().includes(t.toLowerCase()));
    const matchedUses  = LAND_USES.filter(u => raw.toLowerCase().includes(u.toLowerCase()));
    const matchedState = US_STATES.find(s => raw.toUpperCase().includes(s));

    // Build terrain-specific lighting/mood cues
    const terrainCues = {
      Desert:    "warm amber light, red-toned earth, sparse dry vegetation, dramatic shadow contrast",
      "Red rock":"terracotta cliffs, layered sandstone formations, dusty orange tones",
      Mountain:  "elevation haze, pine-forested ridgelines, dramatic cloud shadows across peaks",
      Hilltop:   "elevated vantage point, rolling terrain visible below, open sky dominant",
      Wooded:    "dappled light through tree canopy, rich green foliage, forest floor detail",
      Forested:  "dense tree coverage, filtered golden light, deep greens and browns",
      Timberland:"tall timber stands, logging road, misty morning light through trees",
      Lakefront: "mirror-still water reflection, soft morning mist, shoreline foreground detail",
      Riverfront:"flowing water catching light, riparian vegetation, gentle bank curvature",
      Waterfront:"calm water expanse, golden reflections, horizon-level waterline",
      Creekfront:"winding creek with rocks and reeds, lush green banks, dappled light",
      Coastal:   "sea breeze atmosphere, salt grass dunes, ocean horizon in background",
      "Ocean-view":"elevated coastal terrain, Pacific or Atlantic ocean visible, coastal fog",
      Farmland:  "cultivated rows or open pasture, big sky, rich fertile earth tones",
      Pasture:   "rolling green grass, gentle slope, open grazing land with soft sky",
      Rural:     "quiet countryside, winding dirt road, open fields, minimal infrastructure",
      Valley:    "broad valley floor, mountain ridges framing both sides, river or meadow",
      Flat:      "expansive level ground, wide 180-degree horizon, dramatic cloudscape above",
      Sloped:    "gentle gradient terrain, natural drainage patterns, layered elevation",
      Cleared:   "open land with stumps or grass, recent clearing, full sky visibility",
      Hunting:   "dense brush and tree line, natural wildlife habitat, dawn mist",
      Recreational:"varied terrain with open space, trees, and natural features",
      "Off-grid": "remote backcountry, no infrastructure visible, raw wilderness feel",
      Camping:   "forest clearing, level ground, surrounded by trees, peaceful setting",
    };

    const stateStyle = {
      AZ: "Arizona desert palette: terracotta, sage green, dusty rose, golden hour shadows",
      NM: "New Mexico high desert: adobe tones, lavender shadows, vast plateau",
      UT: "Utah canyon country: red rock formations, orange mesas, turquoise sky",
      CO: "Colorado: snow-capped peaks or alpine meadow, crisp mountain air",
      TX: "Texas: big sky, rolling plains or Hill Country cedar, warm earth",
      FL: "Florida: palmetto scrub, pine flatwoods, bright subtropical light",
      TN: "Tennessee: rolling green hills, hardwood forest, morning mist in hollows",
      AR: "Arkansas: Ozark woodland, creek valleys, dappled forest light",
      MO: "Missouri: oak-hickory forest, limestone bluffs, open river bottom",
      OR: "Oregon: Pacific Northwest forest, mossy greens, overcast diffused light",
      WA: "Washington: evergreen forest, volcanic peaks in distance, cool mist",
      ID: "Idaho: sagebrush plains or pine forest, wide river valleys",
      MT: "Montana: Big Sky country, grassland prairie, distant mountain range",
      WY: "Wyoming: high plains, Wind River or Bighorn backdrop, open range",
      NV: "Nevada: basin-and-range desert, sparse vegetation, dramatic rock outcrops",
      CA: "California: golden oak savanna or coastal chaparral, warm California light",
    };

    const terrainLines = matchedTypes
      .filter(t => terrainCues[t])
      .map(t => `- ${t}: ${terrainCues[t]}`);

    const useLine = matchedState && stateStyle[matchedState]
      ? `\n- State-specific palette (${matchedState}): ${stateStyle[matchedState]}`
      : matchedState
      ? `\n- Location: ${matchedState} — reflect regional landscape character and native vegetation`
      : "";

    const usesLine = matchedUses.length
      ? `\nIntended land use context: ${matchedUses.join(", ")} — the landscape should feel appropriate for this purpose.`
      : "";

    const terrainSection = terrainLines.length
      ? `\nTerrain-specific visual cues:\n${terrainLines.join("\n")}`
      : "";

    // Lighting based on terrain
    const isWater = matchedTypes.some(t => ["Lakefront","Riverfront","Waterfront","Creekfront","Coastal","Ocean-view"].includes(t));
    const isDesert = matchedTypes.some(t => ["Desert","Red rock"].includes(t));
    const isForest = matchedTypes.some(t => ["Wooded","Forested","Timberland"].includes(t));
    const lightingNote = isWater
      ? "Soft golden-hour light with water reflections. Mist or haze near the waterline."
      : isDesert
      ? "Low-angle warm light casting long shadows across the terrain. Rich amber and sienna tones."
      : isForest
      ? "Filtered morning light through canopy. Rich greens, deep shadows, atmospheric mist."
      : "Natural golden-hour or warm midday light with soft shadows and strong horizon.";

    setGeneratedPrompt(
`Photorealistic landscape photograph for vacant land real estate marketing.
${refBlock ? `\n${refBlock}\n` : ""}
Subject: ${desc}
${usesLine}
Composition:
- Wide open frame — sky occupies at least 40% of the image
- Strong horizon line, expansive sense of space and freedom
- No people, structures, vehicles, power lines, or text visible
- Landscape or wide cinematic orientation
- Rich foreground detail transitioning to open mid-ground and distant horizon
${terrainSection}
Lighting: ${lightingNote}
${useLine}
Color palette:
- Earthy, grounded tones: warm greens, dusty tans, harvest golds, muted earth
- Brand reference colors: forest green #3F6B55, warm taupe #635752, harvest gold #E5A94D
- Avoid cold blues, neon saturation, or artificial HDR looks

Mood: vast, peaceful, aspirational — conveys land ownership, legacy, and possibility

Technical requirements:
- Photorealistic — NOT illustrated, painted, or stylized
- The lower 60% of the image will have a dark gradient overlay in production — ensure the upper 40% (sky, horizon) has strong visual interest and detail
- High tonal contrast between land and sky
- 16:9 or wider aspect ratio preferred`
    );
  };

  const copyPrompt = () => {
    navigator.clipboard.writeText(generatedPrompt);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleExport = () => {
    setExporting(true);
    const { w, h } = getWH();
    const offscreen = document.createElement("canvas");
    offscreen.width = w;
    offscreen.height = h;
    const exportState = { ...canvasState, canvasW: w, canvasH: h };
    offscreen.style.cssText = "position:fixed;left:-99999px;top:0;";
    document.body.appendChild(offscreen);
    drawOnCanvas(offscreen, exportState, LOGO).then(() => {
      const dataUrl = offscreen.toDataURL("image/png");
      document.body.removeChild(offscreen);
      const link = document.createElement("a");
      const szLabel = CANVAS_SIZES[canvasSizeIdx]?.label?.toLowerCase().replace(/\s+/g, "-") || "custom";
      link.download = `dealflow-${szLabel}-${w}x${h}.png`;
      link.href = dataUrl;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      setExporting(false);
    }).catch(() => {
      document.body.removeChild(offscreen);
      setExporting(false);
    });
  };

  const applyTemplate = (tplId) => {
    if (tplId === "listing") {
      setTextLayers([
        { ...defaultTextLayer(0), text: "Pristine Land — Yavapai County, AZ", size: 72, color: "#FFFEF6", yPct: 63 },
        { ...defaultTextLayer(1), text: "$24,900", size: 56, color: "#E5A94D", yPct: 76 },
        { id: Date.now()+2, label: "Details", text: "5.03 Acres  |  Road Access  |  Zoned Residential", font: FONT_FAMILIES[1].css, weight: "400", size: 28, color: "#F6F4E3", align: "left", shadow: false, shadowColor: "#1A1A1A", xPct: 6, yPct: 85 },
      ]);
      setShowGradient(true);
      setGradDirection("bottom");
      setGradIntensity(75);
      setGoldRules([{ id: 1, widthPct: 27, yPct: 60 }]);
    } else if (tplId === "tip") {
      setTextLayers([
        { ...defaultTextLayer(0), text: "Land Is the Simplest Investment", size: 64, color: "#3F6B55", shadow: false, yPct: 38 },
        { ...defaultTextLayer(1), text: "No tenants, no toilets, no repairs. Vacant land is hands-off real estate.", font: FONT_FAMILIES[1].css, weight: "400", size: 26, color: "#635752", shadow: false, yPct: 58 },
      ]);
      setShowGradient(false);
      setGoldRules([{ id: 1, widthPct: 28, yPct: 35 }]);
    } else if (tplId === "testimonial") {
      setTextLayers([
        { ...defaultTextLayer(0), text: "The process was seamless. DealFlow made selling simple and fast.", size: 52, color: "#FFFEF6", shadow: true, yPct: 45 },
        { ...defaultTextLayer(1), text: "— Happy Seller, Arizona", font: FONT_FAMILIES[1].css, weight: "400", size: 26, color: "#E5A94D", shadow: false, yPct: 72 },
      ]);
      setShowGradient(true);
      setGradDirection("bottom");
      setGradIntensity(80);
      setGoldRules([{ id: 1, widthPct: 25, yPct: 69 }]);
    } else if (tplId === "stats") {
      setTextLayers([
        { ...defaultTextLayer(0), text: "Deal Closed This Week", size: 64, color: "#FFFEF6", shadow: true, yPct: 20 },
        { ...defaultTextLayer(1), text: "$32,500", size: 80, color: "#E5A94D", shadow: true, yPct: 48 },
        { id: Date.now()+2, label: "Stat 2", text: "5.2 Acres", font: FONT_FAMILIES[0].css, weight: "700", size: 52, color: "#FFFEF6", align: "left", shadow: true, shadowColor: "#1A1A1A", xPct: 38, yPct: 48 },
        { id: Date.now()+3, label: "Stat 3", text: "18 Days to Close", font: FONT_FAMILIES[0].css, weight: "700", size: 52, color: "#FFFEF6", align: "left", shadow: true, shadowColor: "#1A1A1A", xPct: 65, yPct: 48 },
      ]);
      setShowGradient(true);
      setGradDirection("bottom");
      setGradIntensity(65);
      setGoldRules([{ id: 1, widthPct: 15, yPct: 17 }]);
    }
  };

  // ── Styles ──

  const tabBtn = (id, label) => (
    <button
      key={id}
      onClick={() => setTab(id)}
      style={{
        flex: 1, padding: "9px 6px", borderRadius: 8, border: "none",
        background: tab === id ? C.DUSTY_PINE : "transparent",
        color: tab === id ? C.WARM_WHITE : "#9A9087",
        fontWeight: tab === id ? 700 : 500,
        cursor: "pointer", fontSize: 12,
        fontFamily: "'DM Sans',Inter,sans-serif",
        boxShadow: tab === id ? "0 2px 10px rgba(63,107,85,0.28)" : "none",
        letterSpacing: tab === id ? "0" : "0.01em",
      }}
    >
      {label}
    </button>
  );

  const toggle = (val, onToggle, label) => (
    <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 12 }}>
      <span style={{ fontSize: 12, fontWeight: 500, color: C.TAUPE }}>{label}</span>
      <div style={{ display: "flex", background: "#F0EDE6", borderRadius: 7, padding: 3, gap: 2 }}>
        {[{l:"On",v:true},{l:"Off",v:false}].map(opt => (
          <button
            key={opt.l}
            onClick={() => onToggle(opt.v)}
            style={{
              padding: "4px 14px", borderRadius: 5, border: "none",
              background: val === opt.v
                ? (opt.v ? C.DUSTY_PINE : "#fff")
                : "transparent",
              color: val === opt.v
                ? (opt.v ? C.WARM_WHITE : C.TAUPE)
                : "#B0A89E",
              fontWeight: val === opt.v ? 600 : 400,
              fontSize: 11, cursor: "pointer",
              fontFamily: "'DM Sans',Inter,sans-serif",
              boxShadow: val === opt.v ? "0 1px 4px rgba(0,0,0,0.1)" : "none",
            }}
          >
            {opt.l}
          </button>
        ))}
      </div>
    </div>
  );

  const { w: previewW, h: previewH } = getWH();
  const previewAspect = previewH / previewW;

  return (
    <div style={{ minHeight: "100vh", background: "linear-gradient(160deg, #EDE9DC 0%, #E4DFD0 100%)", fontFamily: "'DM Sans',Inter,sans-serif", display: "flex", flexDirection: "column" }}>

      {/* Header */}
      <div style={{ background: `linear-gradient(90deg, #2E5240 0%, ${C.DUSTY_PINE} 60%, #4A7A62 100%)`, padding: "13px 28px", display: "flex", alignItems: "center", justifyContent: "space-between", boxShadow: "0 2px 20px rgba(30,60,45,0.35)" }}>
        <div style={{ display: "flex", alignItems: "center", gap: 14 }}>
          <img src={LOGO} style={{ height: 34, objectFit: "contain", filter: "brightness(1.05)" }} alt="DealFlow" />
          <div style={{ width: 1, height: 28, background: "rgba(255,255,255,0.2)" }} />
          <div>
            <div style={{ color: C.WARM_WHITE, fontWeight: 700, fontSize: 15, letterSpacing: "0.01em" }}>Social Post Builder</div>
            <div style={{ color: C.HARVEST_GOLD, fontSize: 10, fontStyle: "italic", letterSpacing: "0.05em", opacity: 0.9 }}>River of Deals</div>
          </div>
        </div>
        <div style={{ fontSize: 10, color: "rgba(255,255,255,0.35)", letterSpacing: "0.1em", textTransform: "uppercase" }}>v4</div>
      </div>

      <div style={{ display: "flex", flex: 1, flexWrap: "wrap" }}>

        {/* Left Panel */}
        <div style={{ width: 420, minWidth: 340, background: "#FAFAF6", display: "flex", flexDirection: "column", boxShadow: "3px 0 24px rgba(0,0,0,0.07)", maxHeight: "calc(100vh - 64px)", overflowY: "auto" }}>

          {/* Tabs */}
          <div style={{ padding: "14px 16px 12px", borderBottom: "1px solid #E8E3DA", position: "sticky", top: 0, background: "#FAFAF6", zIndex: 10 }}>
            <div style={{ display: "flex", background: "#EEEAE0", borderRadius: 10, padding: 4, gap: 3 }}>
              {tabBtn("prompt", "🍌 Prompt")}
              {tabBtn("build", "✏️ Build")}
              {tabBtn("export", "📥 Export")}
            </div>
          </div>

          <div style={{ flex: 1, padding: "22px 20px" }}>

            {/* ─── PROMPT TAB ─── */}
            {tab === "prompt" && (
              <div style={{ display: "flex", flexDirection: "column", gap: 18 }}>
                <div style={{ background: "linear-gradient(135deg, #FBF6E8 0%, #F5EDD6 100%)", border: "1px solid #E5C97060", borderRadius: 12, padding: "16px 18px", boxShadow: "0 2px 8px rgba(229,169,77,0.08)" }}>
                  <div style={{ fontWeight: 700, color: C.DUSTY_PINE, fontSize: 14, marginBottom: 5, letterSpacing: "0.01em" }}>🍌 Nano Banana Prompt Builder</div>
                  <div style={{ fontSize: 12, color: "#7A7068", lineHeight: 1.6 }}>Build a brand-aligned prompt → paste into <b style={{ color: C.DUSTY_PINE }}>Gemini → Create Images</b> → upload result as background.</div>
                </div>

                {/* Description */}
                <Section title="Describe your image">
                  <div style={{ position: "relative" }}>
                    <textarea
                      value={promptDesc}
                      onChange={e => setPromptDesc(e.target.value)}
                      placeholder="e.g. aerial view of red rock canyon land in Arizona at sunset..."
                      rows={3}
                      style={{ ...inputSt, resize: "vertical", paddingRight: 36 }}
                    />
                    {promptDesc && (
                      <button onClick={() => setPromptDesc("")} style={{ position: "absolute", top: 6, right: 6, background: "#63575230", border: "none", borderRadius: 4, width: 22, height: 22, cursor: "pointer", color: C.TAUPE, fontSize: 14, fontWeight: 700, lineHeight: 1, display: "flex", alignItems: "center", justifyContent: "center" }}>×</button>
                    )}
                  </div>
                </Section>

                {/* Reference image upload */}
                <Section title="Reference Image (optional)">
                  <div style={{ fontSize: 11, color: "#63575288", marginBottom: 8 }}>Upload a reference photo, describe what you see, and the prompt will instruct Gemini to recreate a similar scene in the DealFlow style.</div>
                  {refImageData ? (
                    <div>
                      <div style={{ position: "relative", marginBottom: 10 }}>
                        <img src={refImageData} alt="ref" style={{ width: "100%", borderRadius: 8, maxHeight: 140, objectFit: "cover", display: "block" }} />
                        <button onClick={() => { setRefImageData(null); setRefImageDesc(""); }} style={{ position: "absolute", top: 4, right: 4, background: "#e05050", color: "#fff", border: "none", borderRadius: 4, padding: "2px 7px", cursor: "pointer", fontSize: 12, fontWeight: 700 }}>×</button>
                      </div>
                      <div style={{ fontSize: 11, fontWeight: 600, color: C.TAUPE, marginBottom: 4 }}>Describe what you see in this image</div>
                      <textarea
                        value={refImageDesc}
                        onChange={e => setRefImageDesc(e.target.value)}
                        placeholder="e.g. red rock canyon, late afternoon light, sparse desert scrub, wide valley below..."
                        rows={3}
                        style={{ ...inputSt, resize: "vertical" }}
                      />
                      <div style={{ fontSize: 10, color: "#63575266", marginTop: 4 }}>Also attach this image directly in Gemini alongside the generated prompt for best results.</div>
                    </div>
                  ) : (
                    <div onClick={() => refImageRef.current.click()} style={{ border: "2px dashed #3F6B5560", borderRadius: 8, padding: "20px", textAlign: "center", cursor: "pointer", color: C.DUSTY_PINE, fontSize: 13, background: "#3F6B5508" }}>
                      + Upload reference image
                    </div>
                  )}
                  <input ref={refImageRef} type="file" accept="image/*" style={{ display: "none" }} onChange={handleRefImage} />
                </Section>

                {/* Land type quick-buttons */}
                <Section title="Land Type">
                  <div style={{ display: "flex", flexWrap: "wrap", gap: 6 }}>
                    {LAND_TYPES.map(lt => (
                      <button
                        key={lt}
                        onClick={() => setPromptDesc(d => d ? d + ", " + lt : lt)}
                        style={{ padding: "5px 10px", borderRadius: 20, border: "1.5px solid #3F6B5540", background: "#3F6B5510", color: C.DUSTY_PINE, fontSize: 11, fontWeight: 600, cursor: "pointer" }}
                      >
                        {lt}
                      </button>
                    ))}
                  </div>
                </Section>

                {/* Land Use quick-buttons */}
                <Section title="Land Use">
                  <div style={{ display: "flex", flexWrap: "wrap", gap: 6 }}>
                    {LAND_USES.map(lu => (
                      <button
                        key={lu}
                        onClick={() => setPromptDesc(d => d ? d + ", " + lu : lu)}
                        style={{ padding: "5px 10px", borderRadius: 20, border: "1.5px solid #63575240", background: "#63575210", color: C.TAUPE, fontSize: 11, fontWeight: 600, cursor: "pointer" }}
                      >
                        {lu}
                      </button>
                    ))}
                  </div>
                </Section>

                {/* US State dropdown */}
                <Section title="US State">
                  <select
                    defaultValue=""
                    onChange={e => {
                      const st = e.target.value;
                      if (st) setPromptDesc(d => d ? d + ", " + st : st);
                      e.target.value = "";
                    }}
                    style={{ ...inputSt, cursor: "pointer" }}
                  >
                    <option value="" disabled>Select a state…</option>
                    {US_STATES.map(st => (
                      <option key={st} value={st}>{st}</option>
                    ))}
                  </select>
                </Section>

                <button onClick={buildPrompt} style={{ padding: "13px", background: `linear-gradient(135deg, #2E5240 0%, ${C.DUSTY_PINE} 100%)`, color: C.WARM_WHITE, border: "none", borderRadius: 10, fontWeight: 700, cursor: "pointer", fontSize: 13, letterSpacing: "0.02em", boxShadow: "0 4px 14px rgba(46,82,64,0.35)", fontFamily: "'DM Sans',Inter,sans-serif" }}>
                  ✨ Generate Prompt
                </button>

                {generatedPrompt && (
                  <div>
                    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
                      <div style={{ display: "flex", alignItems: "center", gap: 7 }}>
                        <div style={{ width: 3, height: 12, borderRadius: 2, background: C.HARVEST_GOLD }} />
                        <div style={{ fontSize: 10, fontWeight: 700, color: "#9A9087", letterSpacing: "0.12em", textTransform: "uppercase" }}>Your Prompt</div>
                      </div>
                      <button onClick={() => setGeneratedPrompt("")} style={{ background: "none", border: "none", color: "#C0B8AE", fontSize: 11, cursor: "pointer", fontWeight: 600, padding: "2px 6px", fontFamily: "'DM Sans',Inter,sans-serif" }}>Clear ×</button>
                    </div>
                    <div style={{ background: "#FDFCF9", border: "1px solid #DDD8CE", borderRadius: 10, padding: "13px 15px", fontSize: 12, color: "#7A7068", lineHeight: 1.7, whiteSpace: "pre-wrap", maxHeight: 240, overflowY: "auto", boxShadow: "inset 0 1px 3px rgba(0,0,0,0.04)" }}>{generatedPrompt}</div>
                    <button onClick={copyPrompt} style={{ marginTop: 8, width: "100%", padding: "11px", background: copied ? C.DUSTY_PINE : C.HARVEST_GOLD, color: C.WARM_WHITE, border: "none", borderRadius: 10, fontWeight: 700, cursor: "pointer", fontSize: 13, boxShadow: copied ? "0 4px 12px rgba(63,107,85,0.3)" : "0 4px 12px rgba(229,169,77,0.3)", fontFamily: "'DM Sans',Inter,sans-serif" }}>
                      {copied ? "✓ Copied!" : "📋 Copy Prompt"}
                    </button>
                    <div style={{ marginTop: 10, fontSize: 11, color: "#7A7068", lineHeight: 1.8, background: "#fff", border: "1px solid #E8E3DA", borderRadius: 10, padding: "11px 14px", boxShadow: "0 1px 4px rgba(0,0,0,0.04)" }}>
                      <b>Steps:</b><br />
                      1. Copy prompt above<br />
                      2. Go to <a href="https://gemini.google.com" target="_blank" rel="noreferrer" style={{ color: C.HARVEST_GOLD }}>gemini.google.com</a><br />
                      3. Select Create Images from tools<br />
                      4. Paste and generate and download<br />
                      5. Upload in the Build tab background section
                    </div>
                  </div>
                )}
              </div>
            )}

            {/* ─── BUILD TAB ─── */}
            {tab === "build" && (
              <div style={{ display: "flex", flexDirection: "column", gap: 0 }}>

                {/* Templates (collapsible) */}
                <div style={{ marginBottom: 26, border: "1px solid #E8E3DA", borderRadius: 12, overflow: "hidden", boxShadow: "0 1px 4px rgba(0,0,0,0.04)" }}>
                  <div
                    onClick={() => setTemplatesOpen(o => !o)}
                    style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "11px 16px", cursor: "pointer", background: templatesOpen ? "linear-gradient(135deg, #F6F4E8 0%, #EDE9DC 100%)" : "#F5F3EE" }}
                  >
                    <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                      <div style={{ width: 3, height: 13, borderRadius: 2, background: C.HARVEST_GOLD }} />
                      <span style={{ fontSize: 10, fontWeight: 700, color: "#9A9087", textTransform: "uppercase", letterSpacing: "0.13em" }}>Templates</span>
                      <span style={{ fontSize: 10, color: "#B0A89E", fontStyle: "italic" }}>optional</span>
                    </div>
                    <span style={{ fontSize: 16, color: "#B0A89E", fontWeight: 400 }}>{templatesOpen ? "−" : "+"}</span>
                  </div>
                  {templatesOpen && (
                    <div style={{ padding: "12px 16px 16px", display: "flex", flexDirection: "column", gap: 6, background: "#fff" }}>
                      <div style={{ fontSize: 11, color: "#B0A89E", marginBottom: 6 }}>Click to pre-fill text layers as a starting point.</div>
                      {TEMPLATES.map(t => (
                        <button
                          key={t.id}
                          onClick={() => applyTemplate(t.id)}
                          style={{ padding: "10px 14px", borderRadius: 8, border: "1px solid #E8E3DA", background: "#FAFAF6", color: C.TAUPE, fontWeight: 500, cursor: "pointer", textAlign: "left", fontSize: 13, fontFamily: "'DM Sans',Inter,sans-serif" }}
                        >
                          {t.label}
                        </button>
                      ))}
                    </div>
                  )}
                </div>

                {/* Background Photo */}
                <Section title="Background Photo">
                  <div style={{ display: "flex", flexWrap: "wrap", gap: 8, marginBottom: 8 }}>
                    {allBgs.map((bg, i) => (
                      <div
                        key={i}
                        onClick={() => setBgIdx(i)}
                        title={bg.label}
                        style={{
                          width: 64, height: 64, backgroundImage: `url(${bg.src})`,
                          backgroundSize: "cover", backgroundPosition: "center",
                          borderRadius: 8, cursor: "pointer",
                          border: `3px solid ${bgIdx === i ? C.HARVEST_GOLD : "transparent"}`,
                          boxShadow: bgIdx === i ? `0 0 0 2px ${C.DUSTY_PINE}` : "none",
                          position: "relative",
                        }}
                      >
                        {bg.custom && <div style={{ position: "absolute", bottom: 2, right: 2, background: C.HARVEST_GOLD, borderRadius: 3, width: 12, height: 12, fontSize: 8, display: "flex", alignItems: "center", justifyContent: "center", color: "white", fontWeight: 700 }}>↑</div>}
                      </div>
                    ))}
                    <div
                      onClick={() => bgFileRef.current.click()}
                      style={{ width: 64, height: 64, borderRadius: 8, border: `2px dashed #3F6B5560`, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", cursor: "pointer", color: C.DUSTY_PINE, fontSize: 22, background: "#3F6B5508" }}
                    >
                      +<span style={{ fontSize: 9, marginTop: 1, color: C.TAUPE }}>Upload</span>
                    </div>
                  </div>
                  <input ref={bgFileRef} type="file" accept="image/*" style={{ display: "none" }} onChange={handleUploadBg} />
                  {toggle(showBg, setShowBg, "Show background image")}
                  {!showBg && (
                    <div>
                      <div style={labelSt}>Solid color</div>
                      <div style={{ display: "flex", flexWrap: "wrap", gap: 6 }}>
                        {BRAND_COLORS.map(bc => (
                          <ColorSwatch key={bc.hex} color={bc.hex} selected={solidColor === bc.hex} onClick={() => setSolidColor(bc.hex)} />
                        ))}
                      </div>
                    </div>
                  )}
                </Section>

                {/* Canvas Size */}
                <Section title="Canvas Size">
                  <div style={{ display: "flex", flexDirection: "column", gap: 6, marginBottom: 10 }}>
                    {CANVAS_SIZES.map((sz, i) => (
                      <button
                        key={sz.label}
                        onClick={() => setCanvasSizeIdx(i)}
                        style={{
                          display: "flex", justifyContent: "space-between", alignItems: "center",
                          padding: "8px 12px", borderRadius: 7,
                          border: `1.5px solid ${canvasSizeIdx === i ? C.HARVEST_GOLD : "#3F6B5530"}`,
                          background: canvasSizeIdx === i ? "#E5A94D22" : "transparent",
                          color: canvasSizeIdx === i ? C.DUSTY_PINE : C.TAUPE,
                          fontWeight: canvasSizeIdx === i ? 700 : 500,
                          cursor: "pointer", fontSize: 12,
                        }}
                      >
                        <span>{sz.label}</span>
                        <span style={{ fontSize: 11, color: "#63575299" }}>{sz.w ? `${sz.w}×${sz.h}` : "custom"}</span>
                      </button>
                    ))}
                  </div>
                  {CANVAS_SIZES[canvasSizeIdx].w === null && (
                    <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
                      <div style={{ flex: 1 }}>
                        <div style={labelSt}>Width</div>
                        <input type="number" value={customW} onChange={e => setCustomW(+e.target.value)} style={inputSt} />
                      </div>
                      <span style={{ color: C.TAUPE, paddingTop: 16 }}>×</span>
                      <div style={{ flex: 1 }}>
                        <div style={labelSt}>Height</div>
                        <input type="number" value={customH} onChange={e => setCustomH(+e.target.value)} style={inputSt} />
                      </div>
                    </div>
                  )}
                </Section>

                {/* Gradient */}
                <Section title="Gradient Overlay">
                  {toggle(showGradient, setShowGradient, "Enable gradient")}
                  {showGradient && (
                    <>
                      <div style={{ marginBottom: 10 }}>
                        <div style={labelSt}>Color</div>
                        <div style={{ display: "flex", flexWrap: "wrap", gap: 6 }}>
                          {BRAND_COLORS.map(bc => (
                            <ColorSwatch key={bc.hex} color={bc.hex} selected={gradColor === bc.hex} onClick={() => setGradColor(bc.hex)} />
                          ))}
                        </div>
                      </div>
                      <div style={{ marginBottom: 10 }}>
                        <div style={labelSt}>Direction</div>
                        <div style={{ display: "flex", gap: 6 }}>
                          {GRADIENT_DIRECTIONS.map(d => (
                            <button
                              key={d.value}
                              onClick={() => setGradDirection(d.value)}
                              style={{
                                flex: 1, padding: "6px 4px", borderRadius: 6,
                                border: `1.5px solid ${gradDirection === d.value ? C.HARVEST_GOLD : "#3F6B5530"}`,
                                background: gradDirection === d.value ? "#E5A94D22" : "transparent",
                                fontSize: 11, color: C.TAUPE, cursor: "pointer",
                              }}
                            >
                              {d.label}
                            </button>
                          ))}
                        </div>
                      </div>
                      <div>
                        <div style={labelSt}>Intensity — {gradIntensity}%</div>
                        <input
                          type="range" min={0} max={100} value={gradIntensity}
                          onChange={e => setGradIntensity(+e.target.value)}
                          style={{ width: "100%", accentColor: C.HARVEST_GOLD }}
                        />
                      </div>
                      <div>
                        <div style={labelSt}>Length — {gradLength}%</div>
                        <input
                          type="range" min={10} max={100} value={gradLength}
                          onChange={e => setGradLength(+e.target.value)}
                          style={{ width: "100%", accentColor: C.HARVEST_GOLD }}
                        />
                      </div>
                    </>
                  )}
                </Section>

                {/* Logo */}
                <Section title="Logo">
                  {toggle(showLogo, setShowLogo, "Show logo")}
                  {showLogo && (
                    <>
                      <div style={{ marginBottom: 10 }}>
                        <div style={labelSt}>Position</div>
                        <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 4 }}>
                          {LOGO_POSITIONS.map(pos => (
                            <button
                              key={pos.id}
                              onClick={() => setLogoPosition(pos.id)}
                              style={{
                                padding: "8px", borderRadius: 6, fontSize: 16,
                                border: `1.5px solid ${logoPosition === pos.id ? C.HARVEST_GOLD : "#3F6B5530"}`,
                                background: logoPosition === pos.id ? "#E5A94D22" : "transparent",
                                cursor: "pointer",
                              }}
                            >
                              {pos.label}
                            </button>
                          ))}
                        </div>
                      </div>
                      <div>
                        <div style={labelSt}>Size — {logoSize}%</div>
                        <input
                          type="range" min={5} max={50} value={logoSize}
                          onChange={e => setLogoSize(+e.target.value)}
                          style={{ width: "100%", accentColor: C.HARVEST_GOLD }}
                        />
                      </div>
                      <div>
                        <div style={labelSt}>Opacity — {logoOpacity}%</div>
                        <input
                          type="range" min={0} max={100} value={logoOpacity}
                          onChange={e => setLogoOpacity(+e.target.value)}
                          style={{ width: "100%", accentColor: C.HARVEST_GOLD }}
                        />
                      </div>
                    </>
                  )}
                </Section>

                {/* Text Layers */}
                <Section title="Text Layers">
                  {textLayers.map((layer, index) => (
                    <TextLayerEditor
                      key={layer.id}
                      layer={layer}
                      index={index}
                      onChange={updateTextLayer}
                      onRemove={removeTextLayer}
                    />
                  ))}
                  <button
                    onClick={addTextLayer}
                    style={{ width: "100%", padding: "10px", borderRadius: 9, border: "1.5px dashed #3F6B5560", background: "#3F6B5508", color: C.DUSTY_PINE, fontWeight: 600, cursor: "pointer", fontSize: 12, fontFamily: "'DM Sans',Inter,sans-serif", letterSpacing: "0.02em" }}
                  >
                    + Add Text Layer
                  </button>
                </Section>

                {/* Badges */}
                <Section title="Badges">
                  <div style={{ fontSize: 11, color: "#63575288", marginBottom: 10 }}>Select one badge to place on the canvas.</div>
                  <div style={{ display: "flex", gap: 8, flexWrap: "wrap", marginBottom: 10 }}>
                    {BUILTIN_BADGES.map(badge => {
                      const active = selectedBadge?.id === badge.id;
                      return (
                        <div
                          key={badge.id}
                          onClick={() => setSelectedBadge(active ? null : badge)}
                          style={{
                            width: 72, cursor: "pointer", borderRadius: 8, overflow: "hidden",
                            border: `3px solid ${active ? C.HARVEST_GOLD : "transparent"}`,
                            boxShadow: active ? `0 0 0 2px ${C.DUSTY_PINE}` : "0 1px 4px rgba(0,0,0,0.12)",
                            background: "#fff",
                          }}
                        >
                          <img src={badge.src} alt={badge.label} style={{ width: "100%", display: "block" }} />
                          <div style={{ fontSize: 10, fontWeight: 600, color: active ? C.DUSTY_PINE : C.TAUPE, textAlign: "center", padding: "4px 2px", background: active ? "#E5A94D22" : "transparent" }}>
                            {badge.label}
                          </div>
                        </div>
                      );
                    })}
                  </div>
                  {selectedBadge && (
                    <div style={{ background: "#F6F4E360", border: "1px solid #3F6B5520", borderRadius: 8, padding: "10px 12px" }}>
                      <div style={labelSt}>Size — {badgeSizePct}%</div>
                      <input type="range" min={5} max={100} value={badgeSizePct} onChange={e => setBadgeSizePct(+e.target.value)} style={{ width: "100%", accentColor: C.HARVEST_GOLD, marginBottom: 6 }} />
                      <div style={labelSt}>X — {badgeXPct}%</div>
                      <input type="range" min={0} max={95} value={badgeXPct} onChange={e => setBadgeXPct(+e.target.value)} style={{ width: "100%", accentColor: C.HARVEST_GOLD, marginBottom: 6 }} />
                      <div style={labelSt}>Y — {badgeYPct}%</div>
                      <input type="range" min={0} max={95} value={badgeYPct} onChange={e => setBadgeYPct(+e.target.value)} style={{ width: "100%", accentColor: C.HARVEST_GOLD }} />
                    </div>
                  )}
                </Section>

                {/* Elements */}
                <Section title="Elements">
                  <div style={{ fontSize: 11, color: "#63575288", marginBottom: 8 }}>Upload images, badges, or stickers to place on the canvas.</div>
                  {uploadedElements.map(el => (
                    <div key={el.id} style={{ border: "1px solid #3F6B5530", borderRadius: 8, padding: "10px 12px", marginBottom: 8, background: "#F6F4E340" }}>
                      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
                        <span style={{ fontSize: 12, fontWeight: 600, color: C.TAUPE }}>{el.label}</span>
                        <span onClick={() => setUploadedElements(prev => prev.filter(e => e.id !== el.id))} style={{ fontSize: 14, color: "#e05050", cursor: "pointer", fontWeight: 700 }}>×</span>
                      </div>
                      <div style={labelSt}>Size — {el.sizePct}%</div>
                      <input type="range" min={5} max={100} value={el.sizePct} onChange={e => setUploadedElements(prev => prev.map(elem => elem.id === el.id ? { ...elem, sizePct: +e.target.value } : elem))} style={{ width: "100%", accentColor: C.HARVEST_GOLD, marginBottom: 6 }} />
                      <div style={labelSt}>X — {el.xPct}%</div>
                      <input type="range" min={0} max={95} value={el.xPct} onChange={e => setUploadedElements(prev => prev.map(elem => elem.id === el.id ? { ...elem, xPct: +e.target.value } : elem))} style={{ width: "100%", accentColor: C.HARVEST_GOLD, marginBottom: 6 }} />
                      <div style={labelSt}>Y — {el.yPct}%</div>
                      <input type="range" min={0} max={95} value={el.yPct} onChange={e => setUploadedElements(prev => prev.map(elem => elem.id === el.id ? { ...elem, yPct: +e.target.value } : elem))} style={{ width: "100%", accentColor: C.HARVEST_GOLD }} />
                    </div>
                  ))}
                  <button onClick={() => elemFileRef.current.click()} style={{ width: "100%", padding: "10px", borderRadius: 9, border: "1.5px dashed #E5A94D90", background: "#FBF7EE", color: "#8A7A50", fontWeight: 600, cursor: "pointer", fontSize: 12, fontFamily: "'DM Sans',Inter,sans-serif" }}>
                    + Upload Image / Badge / Sticker
                  </button>
                  <input ref={elemFileRef} type="file" accept="image/*" style={{ display: "none" }} onChange={handleUploadElement} />

                  {/* Gold Rule elements */}
                  <div style={{ marginTop: 18 }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 10 }}>
                      <div style={{ width: 3, height: 12, borderRadius: 2, background: C.HARVEST_GOLD }} />
                      <span style={{ fontSize: 10, fontWeight: 700, color: "#9A9087", textTransform: "uppercase", letterSpacing: "0.13em" }}>Accent Rule</span>
                    </div>
                    {goldRules.map(rule => (
                      <div key={rule.id} style={{ border: "1px solid #E8DFC8", borderRadius: 10, padding: "12px 14px", marginBottom: 10, background: "#FDFAF3", boxShadow: "0 1px 4px rgba(229,169,77,0.08)" }}>
                        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
                          <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                            <div style={{ width: 24, height: 3, borderRadius: 2, background: rule.color || C.HARVEST_GOLD }} />
                            <span style={{ fontSize: 11, fontWeight: 600, color: "#8A7A50" }}>Accent Rule</span>
                          </div>
                          <span onClick={() => setGoldRules(prev => prev.filter(r => r.id !== rule.id))} style={{ fontSize: 13, color: "#D08080", cursor: "pointer", fontWeight: 700, background: "#FFF0F0", borderRadius: 4, padding: "2px 6px" }}>×</span>
                        </div>
                        <div style={labelSt}>Color</div>
                        <div style={{ display: "flex", flexWrap: "wrap", gap: 6, marginBottom: 10 }}>
                          {BRAND_COLORS.map(bc => (
                            <ColorSwatch
                              key={bc.hex}
                              color={bc.hex}
                              selected={(rule.color || C.HARVEST_GOLD) === bc.hex}
                              onClick={() => setGoldRules(prev => prev.map(r => r.id === rule.id ? { ...r, color: bc.hex } : r))}
                            />
                          ))}
                        </div>
                        <div style={labelSt}>Width — {rule.widthPct}%</div>
                        <input type="range" min={5} max={100} value={rule.widthPct} onChange={e => setGoldRules(prev => prev.map(r => r.id === rule.id ? { ...r, widthPct: +e.target.value } : r))} style={{ width: "100%", accentColor: rule.color || C.HARVEST_GOLD, marginBottom: 6 }} />
                        <div style={labelSt}>X Position — {rule.xPct ?? 0}%</div>
                        <input type="range" min={0} max={95} value={rule.xPct ?? 0} onChange={e => setGoldRules(prev => prev.map(r => r.id === rule.id ? { ...r, xPct: +e.target.value } : r))} style={{ width: "100%", accentColor: rule.color || C.HARVEST_GOLD, marginBottom: 6 }} />
                        <div style={labelSt}>Y Position — {rule.yPct}%</div>
                        <input type="range" min={1} max={99} value={rule.yPct} onChange={e => setGoldRules(prev => prev.map(r => r.id === rule.id ? { ...r, yPct: +e.target.value } : r))} style={{ width: "100%", accentColor: rule.color || C.HARVEST_GOLD }} />
                      </div>
                    ))}
                    <button onClick={() => setGoldRules(prev => [...prev, { id: Date.now(), widthPct: 25, xPct: 0, yPct: 60, color: C.HARVEST_GOLD }])} style={{ width: "100%", padding: "10px", borderRadius: 9, border: "1.5px dashed #E5A94D90", background: "#FBF7EE", color: "#8A7A50", fontWeight: 600, cursor: "pointer", fontSize: 12, fontFamily: "'DM Sans',Inter,sans-serif" }}>
                      + Add Accent Rule
                    </button>
                  </div>
                </Section>

              </div>
            )}

            {/* ─── EXPORT TAB ─── */}
            {tab === "export" && (
              <div style={{ display: "flex", flexDirection: "column", gap: 20 }}>
                <div style={{ background: "linear-gradient(135deg, #F0EDE5 0%, #E8E4D8 100%)", border: "1px solid #DDD8CE", borderRadius: 14, padding: "20px", boxShadow: "0 2px 8px rgba(0,0,0,0.05)" }}>
                  <div style={{ fontSize: 10, fontWeight: 700, color: "#9A9087", textTransform: "uppercase", letterSpacing: "0.13em", marginBottom: 10 }}>Ready to Export</div>
                  <div style={{ display: "flex", alignItems: "baseline", gap: 8, marginBottom: 4 }}>
                    <span style={{ fontFamily: "'Cormorant Garamond',Georgia,serif", fontSize: 28, fontWeight: 600, color: C.DUSTY_PINE, letterSpacing: "-0.01em" }}>{canvasW} × {canvasH}</span>
                    <span style={{ fontSize: 11, color: "#9A9087" }}>px</span>
                  </div>
                  <div style={{ fontSize: 11, color: "#9A9087" }}>{CANVAS_SIZES[canvasSizeIdx]?.label || "Custom size"}</div>
                </div>
                <div style={{ fontSize: 11, color: "#B0A89E", lineHeight: 1.7, background: "#fff", border: "1px solid #E8E3DA", borderRadius: 10, padding: "11px 14px" }}>
                  To change the export size, go to the <b style={{ color: C.TAUPE }}>Build</b> tab → Canvas Size.
                </div>
                <button
                  onClick={handleExport}
                  disabled={exporting}
                  style={{
                    padding: "17px", background: exporting ? "#B0A89E" : `linear-gradient(135deg, #2E5240 0%, ${C.DUSTY_PINE} 100%)`,
                    color: C.WARM_WHITE, border: "none", borderRadius: 12,
                    fontWeight: 700, cursor: exporting ? "not-allowed" : "pointer",
                    fontSize: 15, boxShadow: exporting ? "none" : "0 6px 20px rgba(46,82,64,0.38)",
                    letterSpacing: "0.02em", fontFamily: "'DM Sans',Inter,sans-serif",
                  }}
                >
                  {exporting ? "⏳ Exporting..." : `↓ Export PNG — ${canvasW} × ${canvasH}`}
                </button>
                <div style={{ fontSize: 11, color: "#B0A89E", lineHeight: 1.6, textAlign: "center" }}>
                  Exports all layers, gradient, logo, badges and rules at full resolution.
                </div>
              </div>
            )}

          </div>
        </div>

        {/* Preview Panel */}
        <div style={{ flex: 1, minWidth: 300, padding: "32px 36px", display: "flex", flexDirection: "column", alignItems: "center", gap: 16 }}>
          <div style={{ alignSelf: "flex-start", display: "flex", alignItems: "center", gap: 10 }}>
            <div style={{ width: 3, height: 13, borderRadius: 2, background: C.DUSTY_PINE }} />
            <span style={{ fontSize: 10, fontWeight: 700, color: "#9A9087", letterSpacing: "0.14em", textTransform: "uppercase" }}>Live Preview</span>
            <span style={{ fontSize: 10, color: "#B0A89E", background: "rgba(255,255,255,0.7)", borderRadius: 5, padding: "2px 8px", border: "1px solid #DDD8CE", fontWeight: 600 }}>{canvasW} × {canvasH}</span>
          </div>
          <div style={{ width: "100%", maxWidth: 720, boxShadow: "0 20px 60px rgba(50,80,60,0.18), 0 4px 16px rgba(0,0,0,0.08)", borderRadius: 16, overflow: "hidden", border: "1px solid rgba(255,255,255,0.6)" }}>
            <canvas ref={previewRef} style={{ width: "100%", height: "auto", display: "block" }} />
          </div>
          <div style={{ fontSize: 11, color: "#B0A89E", textAlign: "center", letterSpacing: "0.02em" }}>Live preview · Canvas size selected in Build tab</div>
        </div>

      </div>
    </div>
  );
}
